mapper.select:
SELECT , COUNT(DISTINCT rm.id) AS total_rooms, COUNT(DISTINCT CASE WHEN rh.id IS NOT NULL AND rh.check_in_date <= CURDATE() AND (rh.check_out_date IS NULL OR rh.check_out_date >= CURDATE()) AND rh.deleted_at IS NULL THEN rm.id END) AS occupied_rooms FROM dormitories d LEFT JOIN regions r ON r.id = d.region_id AND r.deleted_at IS NULL LEFT JOIN rooms rm ON rm.dormitory_id = d.id AND rm.deleted_at IS NULL LEFT JOIN residence_histories rh ON rh.room_id = rm.id AND rh.deleted_at IS NULL WHERE d.deleted_at IS NULL
AND (d.name LIKE CONCAT('%', #{keyword}, '%') OR d.address LIKE CONCAT('%', #{keyword}, '%'))
AND d.region_id = #{regionId}
GROUP BY d.id, d.region_id, r.name, d.name, d.dormitory_type, d.address, d.daily_rate, d.sort_order, d.version, d.created_at, d.updated_at ORDER BY d.sort_order ASC, d.id ASC LIMIT #{offset}, #{pageSize}

SELECT COUNT(1) FROM dormitories d WHERE d.deleted_at IS NULL
AND (d.name LIKE CONCAT('%', #{keyword}, '%') OR d.address LIKE CONCAT('%', #{keyword}, '%'))
AND d.region_id = #{regionId}
